def balanced(s):
    """Return True if the parentheses in s are balanced, False otherwise."""
    stack = []
    for c in s:
        if c == '(':
            stack.append(c)
        elif c == ')':
            if not stack:
                return False  # Edge case: no opening parenthesis found
            stack.pop()
    return not stack
